<html dir="rtl" lang="ar"><head>
    <meta charset="utf-8">
    <meta content="width=device-width, initial-scale=1.0" name="viewport">
    <title>شهادة اعتماد IRB - IRB-CERT-2026-0001</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800;900&amp;display=swap" rel="stylesheet">
    <link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&amp;display=swap" rel="stylesheet">
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Amiri:wght@400;700&display=swap');
        
        body { 
            font-family: 'Tajawal', sans-serif; 
            margin: 0; 
            background: #f0f4f8;
        }
        
        .certificate-container {
            max-width: 900px;
            margin: 40px auto;
            background: #fff;
            border: 10px solid #1e3a8a;
            padding: 50px;
            position: relative;
            box-shadow: 0 10px 40px rgba(0,0,0,0.15);
        }
        
        .certificate-header {
            text-align: center;
            border-bottom: 3px solid #1e3a8a;
            padding-bottom: 30px;
            margin-bottom: 30px;
        }
        
        .certificate-header h1 {
            font-family: 'Amiri', serif;
            font-size: 42px;
            color: #1e3a8a;
            margin: 0;
            font-weight: 700;
        }
        
        .certificate-header h2 {
            font-size: 24px;
            color: #374151;
            margin: 10px 0 0 0;
            font-weight: 500;
        }
        
        .certificate-content {
            line-height: 2.2;
            font-size: 18px;
        }
        
        .certificate-content p {
            margin: 15px 0;
        }
        
        .certificate-content .label {
            font-weight: 700;
            color: #1e3a8a;
            display: inline-block;
            min-width: 180px;
        }
        
        .certificate-content .value {
            color: #374151;
        }
        
        .certificate-footer {
            margin-top: 50px;
            padding-top: 30px;
            border-top: 2px solid #e5e7eb;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }
        
        .certificate-footer .seal {
            width: 120px;
            height: 120px;
            border: 4px solid #1e3a8a;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            text-align: center;
            color: #1e3a8a;
            font-weight: 700;
            font-size: 14px;
            flex-direction: column;
        }
        
        .certificate-footer .seal span {
            font-size: 10px;
            margin-top: 5px;
        }
        
        .print-actions {
            text-align: center;
            margin-top: 30px;
            padding: 20px;
            background: #f8fafc;
            border-radius: 10px;
        }
        
        .print-actions button {
            background: #1e3a8a;
            color: white;
            border: none;
            padding: 12px 30px;
            font-size: 16px;
            font-family: 'Tajawal', sans-serif;
            border-radius: 8px;
            cursor: pointer;
            margin: 0 10px;
            transition: all 0.3s ease;
        }
        
        .print-actions button:hover {
            background: #1e40af;
            transform: translateY(-2px);
        }
        
        .print-actions .secondary {
            background: #64748b;
        }
        
        .print-actions .secondary:hover {
            background: #475569;
        }
        
        @media print {
            body { background: #fff; }
            .certificate-container { 
                border-width: 5px; 
                margin: 0; 
                box-shadow: none;
            }
            .print-actions { display: none; }
            .no-print { display: none; }
        }
    </style>
